SELECT c.comment_code AS commentCode, c.notice_code AS noticeCode, c.user_code AS userCode, u.name AS userName, c.content AS content, c.created_at AS createdAt, c.updated_at AS updatedAt, c.is_deleted AS isDeleted, c.deleted_at AS deletedAt, c.deleted_by_code AS deletedByCode, du.name AS deletedByName FROM comments c JOIN notices n ON n.notice_code = c.notice_code JOIN projects p ON p.project_code = n.project_code LEFT JOIN users u ON u.user_code = c.user_code LEFT JOIN users du ON du.user_code = c.deleted_by_code WHERE c.notice_code = #{noticeCode}
AND n.project_code IN
#{code}
AND p.status IN ('OD1', 'OD3')
AND (
( n.project_code IN
#{code}
AND p.status IN ('OD1', 'OD3') )
OR
( n.project_code IN
#{code}
AND p.status = 'OD1' )
)
ORDER BY c.comment_code DESC

